+  const getTtlMs = () =>
+    typeof options?.ttlMs === "function"
+      ? options.ttlMs()
+      : (options?.ttlMs ?? getSessionManagerTtl());
+  const cache = createExpiringMapCache<string, true>({
+    ttlMs: getTtlMs,
+    pruneIntervalMs: resolveSessionManagerCachePruneInterval,
+    clock: options?.clock,
